    methods

        function v = Make( ~, a1, a2 )
            v = OctDouble.MakeConst( a1, a2 );
        end
        function v = OctDouble( in, varargin )
            if nargin == 0
                v.v1 = QuadDouble( [] );
                v.v2 = QuadDouble( [] );
                return
            end
            if nargin >= 2
                for i = 1 : length( varargin )
                    in = OctDouble.Plus( in, varargin{ i } );
                end
            end
            if isa( in, 'OctDouble' )
                v.v1 = in.v1;
                v.v2 = in.v2;
            elseif isa( in, 'QuadDouble' )
                v.v1 = in;
                v.v2 = QuadDouble( zeros( size( in ) ) );
            elseif isa( in, 'DoubleDouble' )
                v.v1 = QuadDouble( in );
                v.v2 = QuadDouble( zeros( size( in ) ) );
            else
                v.v1 = QuadDouble( in );
                v.v2 = QuadDouble( zeros( size( in ) ) );
            end
        end























































































































    end

    methods ( Static )

        function v = ones( varargin )
            v = OctDouble.MakeConst( QuadDouble(ones( varargin{:}, 'double' )), QuadDouble(zeros( varargin{:}, 'double' )) );
        end

        function v = zeros( varargin )
            v = OctDouble.MakeConst( QuadDouble(zeros( varargin{:}, 'double' )), QuadDouble(zeros( varargin{:}, 'double' )) );
        end

        function v = eye( varargin )
            v = OctDouble.MakeConst( QuadDouble(eye( varargin{:}, 'double' )), QuadDouble(zeros( varargin{:}, 'double' )) );
        end

        function v = nan( varargin )
            v = OctDouble.MakeConst( QuadDouble(nan( varargin{:}, 'double' )), QuadDouble(nan( varargin{:}, 'double' )) );
        end

        function v = inf( varargin )
            v = OctDouble.MakeConst( QuadDouble(inf( varargin{:}, 'double' )), QuadDouble(inf( varargin{:}, 'double' )) );
        end
        function v = randn( varargin )
            Size = [ varargin{ : } ];
            if isempty( Size )
                Size = [ 1, 1 ];
            elseif isscalar( Size )
                Size = [ Size, Size ];
            end
            N = prod( Size );
            M = 2 * ceil( 0.5 * N );
            U = OctDouble.rand( M / 2, 1 );
            V = OctDouble.rand( M / 2, 1 );
            R = sqrt( -2 * log( U ) );
            Theta = 2 * OctDouble.pi * V;
            [ S, C ] = sincos( Theta );
            Z1 = R .* C;
            Z2 = R .* S;
            v = reshape( [ Z1, Z2 ].', [ M, 1 ] );
            v.v1 = v.v1( 1 : N );
            v.v2 = v.v2( 1 : N );
            v.v3 = v.v3( 1 : N );
            v.v4 = v.v4( 1 : N );
            v.v5 = v.v5( 1 : N );
            v.v6 = v.v6( 1 : N );
            v.v7 = v.v7( 1 : N );
            v.v8 = v.v8( 1 : N );
            v = reshape( v, Size );
        end

        function v = rand( varargin )
            t = rand( varargin{:}, 'double' );
            v = OctDouble.MakeConst( QuadDouble(t), QuadDouble(eps( t ) .* ( rand( varargin{:}, 'double' ) - 0.5 )) );
        end


        function v = randi( imax, varargin )
            v = OctDouble.MakeConst( QuadDouble(randi( imax, varargin{:}, 'double' )), QuadDouble(zeros( varargin{:}, 'double' )) );
        end










        function s = Sum( v, Dim )
            if isa( v, 'OctDouble' )
                if nargin < 2 || isempty( Dim )
                    Dim = find( size( v.v1 ) > 1, 1 );
                    if isempty( Dim )
                        Dim = 1;
                    end
                end
                Size = size( v.v1 );
                Length = Size( Dim );
                if Length == 0
                    Size = max( 1, Size );
                    s = OctDouble.zeros( Size );
                    return
                end
                Blocks = num2cell( Size );
                Blocks{ Dim } = ones( Length, 1 );
                x1 = mat2cell( v.v1, Blocks{:} );
                x2 = mat2cell( v.v2, Blocks{:} );
                s = OctDouble.MakeConst( x1{ 1 }, x2{ 1 } );
                for i = 2 : Length
                    s = OctDouble.Plus( s, OctDouble.MakeConst( x1{ i }, x2{ i } ) );
                end
            else
                if nargin < 2 || isempty( Dim )
                    Dim = find( size( v ) > 1, 1 );
                    if isempty( Dim )
                        Dim = 1;
                    end
                end
                Size = size( v );
                Length = Size( Dim );
                if Length == 0
                    Size = max( 1, Size );
                    s = OctDouble.zeros( Size );
                    return
                end
                Blocks = num2cell( Size );
                Blocks{ Dim } = ones( Length, 1 );
                x = mat2cell( v, Blocks{:} );
                s = x{ 1 };
                for i = 2 : Length
                    s = OctDouble.Plus( s, x{ i } );
                end
            end
        end

        function c = CumSum( v, Dim )
            if isa( v, 'OctDouble' )
                if nargin < 2 || isempty( Dim )
                    Dim = find( size( v.v1 ) > 1, 1 );
                    if isempty( Dim )
                        Dim = 1;
                    end
                end
                Size = size( v.v1 );
                Length = Size( Dim );
                if Length == 0
                    c = OctDouble.zeros( Size );
                    return
                end
                Blocks = num2cell( Size );
                Blocks{ Dim } = ones( Length, 1 );
                x1 = mat2cell( v.v1, Blocks{:} );
                x2 = mat2cell( v.v2, Blocks{:} );
                s = OctDouble.MakeConst( x1{ 1 }, x2{ 1 } );
                c1 = cell( size( x1 ) );
                c2 = cell( size( x2 ) );
                c1{1} = s.v1;
                c2{1} = s.v2;
                for i = 2 : Length
                    s = OctDouble.Plus( s, OctDouble.MakeConst( x1{ i }, x2{ i } ) );
                    c1{i} = s.v1;
                    c2{i} = s.v2;
                end
            else
                if nargin < 2 || isempty( Dim )
                    Dim = find( size( v ) > 1, 1 );
                    if isempty( Dim )
                        Dim = 1;
                    end
                end
                Size = size( v );
                Length = Size( Dim );
                if Length == 0
                    c = OctDouble.zeros( Size );
                    return
                end
                Blocks = num2cell( Size );
                Blocks{ Dim } = ones( Length, 1 );
                x = mat2cell( v, Blocks{:} );
                s = x{ 1 };
                c1 = cell( size( x ) );
                c2 = cell( size( x ) );
                c1{1} = s;
                c2{1} = zeros( size( s ) );
                for i = 2 : Length
                    s = OctDouble.Plus( s, x{ i } );
                    c1{i} = s.v1;
                    c2{i} = s.v2;
                end
            end
            c = OctDouble.MakeConst( cat( Dim, c1{:} ), cat( Dim, c2{:} ) );
        end


        function s = Prod( v, Dim )
            if isa( v, 'OctDouble' )
                if nargin < 2 || isempty( Dim )
                    Dim = find( size( v.v1 ) > 1, 1 );
                    if isempty( Dim )
                        Dim = 1;
                    end
                end
                Size = size( v.v1 );
                Length = Size( Dim );
                if Length == 0
                    Size = max( 1, Size );
                    s = OctDouble.MakeConst( ones( Size ), zeros( Size ) );
                    return
                end
                Blocks = num2cell( Size );
                Blocks{ Dim } = ones( Length, 1 );
                x1 = mat2cell( v.v1, Blocks{:} );
                x2 = mat2cell( v.v2, Blocks{:} );
                s = OctDouble.MakeConst( x1{ 1 }, x2{ 1 } );
                for i = 2 : Length
                    s = OctDouble.Times( s, OctDouble.MakeConst( x1{ i }, x2{ i } ) );
                end
            else
                if nargin < 2 || isempty( Dim )
