        function v = MakeConst( a1, a2 )
            v = OctDouble;
            if ~isa( a1, 'QuadDouble' ) && ~isempty( a1 )
                a1 = QuadDouble( a1 );
            end
            if ~isa( a2, 'QuadDouble' ) && ~isempty( a2 )
                a2 = QuadDouble( a2 );
            end
            v.v1 = a1;
            v.v2 = a2;
        end














        function Supported = TestSingletonExpansion
            a = ones( 2, 1 );
            b = [];
            c = [];
            try
                b = a + a.';
                c = a .* a.';
            catch
            end
            Supported = all( [ size( b ), size( c ) ] == 2 );
        end
